// Determine period
const now = new Date();
const month = String(now.getMonth() + 1).padStart(2, '0');
const year = now.getFullYear();
const monthName = now.toLocaleDateString('en-US', { month: 'long' });

return {
  json: {
    period: `${year}-${month}`,
    month_name: monthName,
    year: year,
    today: now.toISOString().split('T')[0],
    odoo_url: 'https://erp.insightpulseai.com',
    db: 'odoo',
    uid: 2,
    password: 'admin'
  }
};

const p4Tasks = $('Fetch Month-End Tasks (P4)').first().json.result || [];
const p5Tasks = $('Fetch Tax Tasks (P5)').first().json.result || [];
const period = $('Init Period').first().json;
const today = period.today;

// Month-End stages
const p4Stages = ['Preparation', 'Accruals', 'Review', 'Approval', 'Submitted', 'Closed'];
const p4Closed = ['Closed'];

// Tax stages
const p5Stages = ['Data Collection', 'Computation', 'Internal Review', 'Submission', 'Posted', 'Compliance Closed'];
const p5Closed = ['Compliance Closed'];

function analyzeCluster(tasks, closedStages, allStages) {
  const total = tasks.length;
  const byStage = {};
  allStages.forEach(s => byStage[s] = 0);

  const blockers = [];
  let closedCount = 0;

  tasks.forEach(t => {
    const stageName = t.stage_id ? t.stage_id[1] : 'Unknown';
    byStage[stageName] = (byStage[stageName] || 0) + 1;

    if (closedStages.includes(stageName)) {
      closedCount++;
    }

    // Blocker: overdue and not in closed stage
    if (t.date_deadline && t.date_deadline < today && !closedStages.includes(stageName)) {
      blockers.push({
        id: t.id,
        name: t.name,
        stage: stageName,
        deadline: t.date_deadline,
        assignees: (t.user_ids || []).join(', ')
      });
    }
  });

  return {
    total,
    closed: closedCount,
    progress_pct: total > 0 ? Math.round((closedCount / total) * 100) : 0,
    by_stage: byStage,
    blockers,
    blocker_count: blockers.length
  };
}

const monthEnd = analyzeCluster(p4Tasks, p4Closed, p4Stages);
const taxCompliance = analyzeCluster(p5Tasks, p5Closed, p5Stages);

const overallProgress = (monthEnd.total + taxCompliance.total) > 0
  ? Math.round(((monthEnd.closed + taxCompliance.closed) / (monthEnd.total + taxCompliance.total)) * 100)
  : 0;

return {
  json: {
    period: period.period,
    month_name: period.month_name,
    year: period.year,
    today: today,
    overall_progress_pct: overallProgress,
    month_end_closing: monthEnd,
    tax_compliance: taxCompliance,
    total_blockers: monthEnd.blocker_count + taxCompliance.blocker_count,
    all_blockers: [...monthEnd.blockers, ...taxCompliance.blockers]
  }
};

