const analysis = $('Analyze Close Progress').first().json;
const gptResponse = $json;
const report = gptResponse.choices?.[0]?.message?.content || 'Report generation failed.';

const taskName = `Close Status — ${analysis.month_name} ${analysis.year}`;
const description = `## Auto-Generated Close Status Report\n\n**Period**: ${analysis.month_name} ${analysis.year}\n**Overall Progress**: ${analysis.overall_progress_pct}%\n**Total Blockers**: ${analysis.total_blockers}\n**Generated**: ${analysis.today}\n\n---\n\n${report}\n\n---\n\n### Raw Metrics\n- Month-End: ${analysis.month_end_closing.progress_pct}% (${analysis.month_end_closing.closed}/${analysis.month_end_closing.total})\n- Tax: ${analysis.tax_compliance.progress_pct}% (${analysis.tax_compliance.closed}/${analysis.tax_compliance.total})`;

return {
  json: {
    task_name: taskName,
    description: description,
    report: report,
    analysis: analysis,
    odoo_url: $('Init Period').first().json.odoo_url,
    db: $('Init Period').first().json.db,
    uid: $('Init Period').first().json.uid,
    password: $('Init Period').first().json.password
  }
};

const searchResult = $json.result || [];
const prev = $('Format Report').first().json;

if (searchResult.length > 0) {
  // Update existing task
  return {
    json: {
      action: 'update',
      task_id: searchResult[0].id,
      task_name: prev.task_name,
      description: prev.description,
      report: prev.report,
      analysis: prev.analysis,
      odoo_url: prev.odoo_url,
      db: prev.db,
      uid: prev.uid,
      password: prev.password
    }
  };
} else {
  // Create new task
  return {
    json: {
      action: 'create',
      task_id: null,
      task_name: prev.task_name,
      description: prev.description,
      report: prev.report,
      analysis: prev.analysis,
      odoo_url: prev.odoo_url,
      db: prev.db,
      uid: prev.uid,
      password: prev.password
    }
  };
}

const analysis = $('Analyze Close Progress').first().json;
const report = $('Format Report').first().json.report;
const action = $('Create or Update?').first().json.action;

return {
  json: {
    status: 'ok',
    action_taken: action,
    period: `${analysis.month_name} ${analysis.year}`,
    overall_progress_pct: analysis.overall_progress_pct,
    month_end_progress_pct: analysis.month_end_closing.progress_pct,
    tax_progress_pct: analysis.tax_compliance.progress_pct,
    total_blockers: analysis.total_blockers,
    report_preview: report.substring(0, 500)
  }
};
